#include <ctype.h>
#include <string.h>

int luhn_check(const char *number_string) {
    int sum = 0;
    int double_digit = 0;
    size_t len = strlen(number_string);

    for (size_t i = len; i > 0; i--) {
        char ch = number_string[i - 1];
        if (!isdigit((unsigned char)ch)) {
            return 0;
        }
        int digit = ch - '0';
        if (double_digit) {
            digit *= 2;
            if (digit > 9) digit -= 9;
        }
        sum += digit;
        double_digit = !double_digit;
    }

    return (sum % 10) == 0;
}

#include <cctype>
#include <string>

bool luhn_check(const std::string& number) {
    int sum = 0;
    bool double_digit = false;

    for (int index = static_cast<int>(number.size()) - 1; index >= 0; --index) {
        unsigned char ch = static_cast<unsigned char>(number[index]);
        if (!std::isdigit(ch)) {
            return false;
        }

        int digit = number[index] - '0';
        if (double_digit) {
            digit *= 2;
            if (digit > 9) {
                digit -= 9;
            }
        }

        sum += digit;
        double_digit = !double_digit;
    }

    return sum % 10 == 0;
}

public class Luhn {
    public static boolean luhnCheck(String number) {
        int sum = 0;
        boolean doubleDigit = false;

        for (int i = number.length() - 1; i >= 0; i--) {
            char ch = number.charAt(i);
            if (!Character.isDigit(ch)) {
                return false;
            }
            int digit = ch - '0';
            if (doubleDigit) {
                digit *= 2;
                if (digit > 9) {
                    digit -= 9;
                }
            }
            sum += digit;
            doubleDigit = !doubleDigit;
        }

        return sum % 10 == 0;
    }
}

fun luhnCheck(number: String): Boolean {
    if (number.isEmpty() || number.any { !it.isDigit() }) {
        return false
    }

    var sum = 0
    var doubleDigit = false

    for (index in number.length - 1 downTo 0) {
        var digit = number[index] - '0'
        if (doubleDigit) {
            digit *= 2
            if (digit > 9) {
                digit -= 9
            }
        }
        sum += digit
        doubleDigit = !doubleDigit
    }

    return sum % 10 == 0
}

func luhnCheck(_ number: String) -> Bool {
    let digits = number.compactMap { $0.wholeNumberValue }
    guard digits.count == number.count else { return false }

    var sum = 0
    let reversed = digits.reversed()
    for (index, digit) in reversed.enumerated() {
        if index % 2 == 1 {
            var doubled = digit * 2
            if doubled > 9 {
                doubled -= 9
            }
            sum += doubled
        } else {
            sum += digit
        }
    }

    return sum % 10 == 0
}
